arguments.argument:
if global.gamePaused=false
{
  if init=0 {init=1}
  
  speed=bulletSpeed
  direction+=arcAmt
  image_angle=direction
  
  if arcAmt!=0
  {
    if arcAmt>0 {arcAmt-=falloff}
    else {arcAmt+=falloff}
  }
  if arcAmt>-0.2 and arcAmt<0.2 {arcAmt=0}
  
  if decayTime!=-100
  {
    decayTime-=1
    if decayTime<=0 {instance_destroy()}
  }
}
else {speed=0}
